+    match statement {
+        Statement::Select(_)
+        | Statement::Pragma(_)
+        | Statement::Explain { .. } => true,
+        Statement::Insert(insert) => !insert.returning.is_empty(),
+        Statement::Update(update) => !update.returning.is_empty(),
+        Statement::Delete(delete) => !delete.returning.is_empty(),
